53	int OpenfpgaShell::start(int argc, char** argv) {
54	  reset();
55	
56	  /* Create the command to launch shell in different modes */
57	  openfpga::Command start_cmd("OpenFPGA");
58	  /* Add options to openfpga shell interface */
59	  /* '--interactive', -i': launch the interactive mode */
60	  openfpga::CommandOptionId opt_interactive = start_cmd.add_option(
61	    "interactive", false, "Launch OpenFPGA in interactive mode");
62	  start_cmd.set_option_short_name(opt_interactive, "i");
63	
64	  /* '--file', -f': launch the script mode */
65	  openfpga::CommandOptionId opt_script_mode =
66	    start_cmd.add_option("file", false, "Launch OpenFPGA in script mode");
67	  start_cmd.set_option_require_value(opt_script_mode, openfpga::OPT_STRING);
68	  start_cmd.set_option_short_name(opt_script_mode, "f");
69	
70	  /* '--execute', -x': execute command line(s), separated by ';' */
71	  openfpga::CommandOptionId opt_exec_mode = start_cmd.add_option(
72	    "execute", false, "Execute OpenFPGA command line(s), separated by ';'");
73	  start_cmd.set_option_require_value(opt_exec_mode, openfpga::OPT_STRING);
74	  start_cmd.set_option_short_name(opt_exec_mode, "x");
75	
76	  /* '--batch_execution': execute the script in batch mode.
77	   * Will exit immediately when fatal errors occurred
78	   */
79	  openfpga::CommandOptionId opt_batch_exec =
80	    start_cmd.add_option("batch_execution", false,
81	                         "Launch OpenFPGA in batch  mode when running scripts");
82	  start_cmd.set_option_short_name(opt_batch_exec, "batch");
83	
84	  /* '--version', -v': print version information */
85	  openfpga::CommandOptionId opt_version =
86	    start_cmd.add_option("version", false, "Show OpenFPGA version");
87	  start_cmd.set_option_short_name(opt_version, "v");
88	
89	  /* '--help', -h': print help desk */
90	  openfpga::CommandOptionId opt_help =
91	    start_cmd.add_option("help", false, "Help desk");
92	  start_cmd.set_option_short_name(opt_help, "h");
93	
94	  /* Parse the option, to avoid issues, we use the command name to replace the
95	   * argv[0] */
96	  std::vector<std::string> cmd_opts;
97	  cmd_opts.push_back(start_cmd.name());
98	  for (int iarg = 1; iarg < argc; ++iarg) {
99	    cmd_opts.push_back(std::string(argv[iarg]));
100	  }
101	
102	  openfpga::CommandContext start_cmd_context(start_cmd);
103	  if (false == parse_command(cmd_opts, start_cmd, start_cmd_context)) {
104	    /* Parse fail: Echo the command */
105	    openfpga::print_command_options(start_cmd);
106	  } else {
107	    /* Parse succeed. Branch on options */
108	    /* Show version */
109	    if (true == start_cmd_context.option_enable(start_cmd, opt_version)) {
110	      print_openfpga_version_info();
111	      return 0;
112	    }
113	    /* Start a shell */
114	    if (true == start_cmd_context.option_enable(start_cmd, opt_interactive)) {
115	      shell_.run_interactive_mode(openfpga_ctx_);
116	      return shell_.exit_code();
117	    }
118	
119	    if (true == start_cmd_context.option_enable(start_cmd, opt_exec_mode)) {
120	      shell_.run_execute_mode(
121	        start_cmd_context.option_value(start_cmd, opt_exec_mode).c_str(),
122	        openfpga_ctx_);
123	      return shell_.exit_code();
124	    }
125	
126	    if (true == start_cmd_context.option_enable(start_cmd, opt_script_mode)) {
127	      shell_.run_script_mode(
128	        start_cmd_context.option_value(start_cmd, opt_script_mode).c_str(),
129	        openfpga_ctx_,
130	        start_cmd_context.option_enable(start_cmd, opt_batch_exec));
131	      return shell_.exit_code();
132	    }
133	    /* Reach here there is something wrong, show the help desk */
134	    openfpga::print_command_options(start_cmd);
135	  }
136	
137	  /* Reach here, it means shell execution has critical errors.
138	   * Return a code with fatal errors
139	   */
140	  return 1;
141	}
