21	static ShellCommandId add_openfpga_ext_exec_command(
22	  openfpga::Shell<OpenfpgaContext>& shell,
23	  const ShellCommandClassId& cmd_class_id,
24	  const std::vector<ShellCommandId>& dependent_cmds) {
25	  Command shell_cmd("ext_exec");
26	
27	  /* Add an option '--command_stream' */
28	  CommandOptionId opt_cmdstream = shell_cmd.add_option(
29	    "command", true,
30	    "A string stream which contains the commands to be executed");
31	  shell_cmd.set_option_require_value(opt_cmdstream, openfpga::OPT_STRING);
32	
33	  /* Add command to the Shell */
34	  ShellCommandId shell_cmd_id = shell.add_command(
35	    shell_cmd, "Source a string of commands or execute a script from a file");
36	  shell.set_command_class(shell_cmd_id, cmd_class_id);
37	  shell.set_command_execute_function(shell_cmd_id, call_external_command);
38	
39	  /* Add command dependency to the Shell */
40	  shell.set_command_dependency(shell_cmd_id, dependent_cmds);
41	
42	  return shell_cmd_id;
43	}
