83	void add_basic_commands(openfpga::Shell<OpenfpgaContext>& shell) {
84	  /* Add a new class of commands */
85	  ShellCommandClassId basic_cmd_class = shell.add_command_class("Basic");
86	
87	  Command shell_cmd_exit("exit");
88	  ShellCommandId shell_cmd_exit_id =
89	    shell.add_command(shell_cmd_exit, "Exit the shell");
90	  shell.set_command_class(shell_cmd_exit_id, basic_cmd_class);
91	  shell.set_command_execute_function(shell_cmd_exit_id,
92	                                     [shell]() { shell.exit(); });
93	
94	  /* Version */
95	  Command shell_cmd_version("version");
96	  ShellCommandId shell_cmd_version_id =
97	    shell.add_command(shell_cmd_version, "Show version information");
98	  shell.set_command_class(shell_cmd_version_id, basic_cmd_class);
99	  shell.set_command_execute_function(shell_cmd_version_id,
100	                                     print_openfpga_version_info);
101	
102	  /* Add a hidden command: internal_version */
103	  Command shell_cmd_internal_version("hidden_version");
104	  ShellCommandId shell_cmd_internal_version_id = shell.add_command(
105	    shell_cmd_internal_version, "Show internal version information", true);
106	  shell.set_command_class(shell_cmd_internal_version_id, basic_cmd_class);
107	  shell.set_command_execute_function(shell_cmd_internal_version_id,
108	                                     print_openfpga_version_info);
109	
110	  /* Add 'source' command which can run a set of commands */
111	  add_openfpga_source_command(shell, basic_cmd_class,
112	                              std::vector<ShellCommandId>());
113	
114	  /* Add 'exec_external command which can run system call */
115	  add_openfpga_ext_exec_command(shell, basic_cmd_class,
116	                                std::vector<ShellCommandId>());
117	
118	  /* Note:
119	   * help MUST be the last to add because the linking to execute function will
120	   * do a snapshot on the shell
121	   */
122	  Command shell_cmd_help("help");
123	  ShellCommandId shell_cmd_help_id =
124	    shell.add_command(shell_cmd_help, "Launch help desk");
125	  shell.set_command_class(shell_cmd_help_id, basic_cmd_class);
126	  shell.set_command_execute_function(shell_cmd_help_id,
127	                                     [shell]() { shell.print_commands(); });
128	}
129	
130	} /* end namespace openfpga */
