243	/* Add a command with it description */
244	template<class T>
245	ShellCommandClassId Shell<T>::add_command_class(const char* name) {
246	  /* Ensure that the name is unique in the command list */
247	  std::map<std::string, ShellCommandClassId>::const_iterator name_it = command_class2ids_.find(std::string(name));
248	  if (name_it != command_class2ids_.end()) {
249	    return ShellCommandClassId::INVALID();
250	  }
251	
252	  /* This is a legal name. we can create a new id */
253	  ShellCommandClassId cmd_class = ShellCommandClassId(command_class_ids_.size());
254	  command_class_ids_.push_back(cmd_class);
255	  command_class_names_.push_back(std::string(name));
256	
257	  /* Register the name in the name2id map */
258	  command_class2ids_[std::string(name)] = cmd_class;
259	
260	  /* Register in the fast look-up for commands by classes */
261	  commands_by_classes_.emplace_back();
262	
263	  return cmd_class;
264	} 
