269	template <class T>
270	void Shell<T>::run_interactive_mode(T& context, const bool& quiet_mode) {
271	  if (false == quiet_mode) {
272	    /* Reset timer since it does not come from another mode */
273	    time_start_ = std::clock();
274	
275	    VTR_LOG("Start interactive mode of %s...\n",
276	            name().c_str());
277	
278	    /* Print the title of the shell */
279	    if (!title().empty()) {
280	      VTR_LOG("%s\n", title().c_str());
281	    }
282	  }
283	
284	  /* Wait for users input and execute the command */
285	  initialize_readline(commands4autocomplete_);
286	  std::string cmd_prompt = name() + std::string("> ");
287	  while (true) {
288	    std::string cmd_line = get_user_input(cmd_prompt);
289	    /* If the line is not empty:
290	     * Try to execute the command and
291	     * Add to history 
292	     */
293	    if (!cmd_line.empty()) {
294	      /* Do not allow any hidden command to be directly called by users */
295	      execute_command(cmd_line.c_str(), context, false);
296	    }
297	  }
298	}
