300	template <class T>
301	void Shell<T>::run_script_mode(const char* script_file_name,
302	                               T& context,
303	                               const bool& batch_mode) {
304	
305	  time_start_ = std::clock();
306	
307	  VTR_LOG("Reading script file %s...\n", script_file_name);
308	
309	  /* Print the title of the shell */
310	  if (!title().empty()) {
311	    VTR_LOG("%s\n", title().c_str());
312	  } 
313	
314	  std::string line;
315	
316	  /* Create an input file stream */
317	  std::ifstream fp(script_file_name);
318	
319	  if (!fp.is_open()) {
320	    /* Fail to open the file, ask user to check */
321	    VTR_LOG("Fail to open the script file: %s! Please check its location\n",
322	            script_file_name);
323	    return; 
324	  }
325	
326	  /* Consider that each line may not end due to the continued line charactor 
327	   * Use cmd_line to conjunct multiple lines 
328	   */
329	  std::string cmd_line;
330	
331	  /* Read line by line */
332	  while (getline(fp, line)) {
333	    /* Skip empty line */
334	    if (true == line.empty()) {
335	      continue;
336	    }
337	
338	    /* If the line that starts with '#', it is commented, we can skip */ 
339	    if ('#' == line.front()) {
340	      continue;
341	    }
342	    /* Try to split the line with '#', the string before '#' is the read command we want */
343	    std::string cmd_part = line;
344	    std::size_t cmd_end_pos = line.find_first_of('#');
345	    /* If the full line has '#', we need the part before it */
346	    if (cmd_end_pos != std::string::npos) {
347	      cmd_part = line.substr(0, cmd_end_pos);
348	    }
349

350	    /* Remove the space at the end of the line
351	     * So that we can check easily if there is a continued line in the end  
352	     */
353	    StringToken cmd_part_tokenizer(cmd_part);
354	    cmd_part_tokenizer.rtrim(std::string(" "));
355	    cmd_part = cmd_part_tokenizer.data();
356	
357	    /* If the line ends with '\', this is a continued line, parse the next until it ends */
358	    if ('\\' == cmd_part.back()) {
359	      /* Pop up the last charactor and conjunct to cmd_line */
360	      cmd_part.pop_back();
361	 
362	      if (!cmd_part.empty()) {
363	        cmd_line += cmd_part; 
364	      }
365	      /* Not finished yet. Parse the next line */
366	      continue;
367	    } else {
368	      /* End of this line, if cmd_line is empty, 
369	       * there is no previous lines, cache the part we have
370	       * and then execute the command 
371	       */
372	      cmd_line += cmd_part;
373	    }
374	
375	    /* Remove the space at the beginning of the line */
376	    StringToken cmd_line_tokenizer(cmd_line);
377	    cmd_line_tokenizer.ltrim(std::string(" "));
378	    cmd_line = cmd_line_tokenizer.data();
379	
380	    /* Process the command only when the full command line in ended */
381	    if (!cmd_line.empty()) {
382	      VTR_LOG("\nCommand line to execute: %s\n", cmd_line.c_str());
383	      /* Do not allow any hidden command to be directly called by users */
384	      int status = execute_command(cmd_line.c_str(), context, false);
385	      /* Empty the line ready to start a new line */
386	      cmd_line.clear();
387	
388	      /* Check the execution status of the command, 
389	       * if fatal error happened, we should abort immediately 
390	       */
391	      if (CMD_EXEC_FATAL_ERROR == status) {
392	        VTR_LOG("Fatal error occurred!\n");
393	        /* If in the batch mode, we will exit with errors */ 
394	        VTR_LOGV(batch_mode, "%s Abort\n", name_.c_str());
395	        if (batch_mode) {
396	          exit(CMD_EXEC_FATAL_ERROR);
397	        }
398	        /* If not in the batch mode, we will got to interactive mode */ 
399	        VTR_LOGV(!batch_mode, "Enter interactive mode\n");
400	        break;
401	      }
402	    }
403	  }
404	  fp.close();
405	
406	  /* If not in batch mode, switch to interactive mode, stay tuned */
407	  if (!batch_mode) {
408	    run_interactive_mode(context, true); 
409	  }
410	}
