412	template <class T>
413	void Shell<T>::run_execute_mode(const char* command_lines, T& context) {
414	  time_start_ = std::clock();
415	
416	  /* Print the title of the shell */
417	  if (!title().empty()) {
418	    VTR_LOG("%s\n", title().c_str());
419	  }
420	
421	  std::string exec_lines = command_lines ? command_lines : "";
422	  size_t cmd_begin = 0;
423	
424	  while (cmd_begin < exec_lines.size()) {
425	    size_t cmd_end = exec_lines.find(';', cmd_begin);
426	    if (std::string::npos == cmd_end) {
427	      cmd_end = exec_lines.size();
428	    }
429	
430	    std::string cmd_line = exec_lines.substr(cmd_begin, cmd_end - cmd_begin);
431	
432	    StringToken cmd_line_tokenizer(cmd_line);
433	    cmd_line_tokenizer.ltrim(std::string(" \t\n\r"));
434	    cmd_line_tokenizer.rtrim(std::string(" \t\n\r"));
435	    cmd_line = cmd_line_tokenizer.data();
436	
437	    if (!cmd_line.empty()) {
438	      VTR_LOG("\nCommand line to execute: %s\n", cmd_line.c_str());
439	      /* Do not allow any hidden command to be directly called by users */
440	      int status = execute_command(cmd_line.c_str(), context, false);
441	      if (CMD_EXEC_FATAL_ERROR == status) {
442	        VTR_LOG("Fatal error occurred!\n");
443	        break;
444	      }
445	    }
446	
447	    if (cmd_end == exec_lines.size()) {
448	      break;
449	    }

450	    cmd_begin = cmd_end + 1;
451	  }
452	}
