454	template <class T>
455	void Shell<T>::print_commands(const bool& show_hidden) const {
456	  /* Print the commands by their classes */
457	  for (const ShellCommandClassId& cmd_class : command_class_ids_) {
458	    /* If there are only hidden commands inside, do not even need to show the class name here */
459	    bool hidden_class = true;
460	    for (const ShellCommandId& cmd : commands_by_classes_[cmd_class]) {
461	      if (!command_hidden_[cmd]) {
462	        hidden_class = false;
463	        break;
464	      }
465	    }
466	    
467	    /* Print the class name */
468	    if (!show_hidden && hidden_class) {
469	      continue;
470	    }
471	    VTR_LOG("%s:\n", command_class_names_[cmd_class].c_str());
472	
473	    for (const ShellCommandId& cmd : commands_by_classes_[cmd_class]) {
474	      if (!show_hidden && command_hidden_[cmd]) {
475	        continue;
476	      }
477	      VTR_LOG("\t%s\n", commands_[cmd].name().c_str());
478	    }
479	
480	    /* Put a new line in the end as a splitter */
481	    VTR_LOG("\n");
482	  }
483	
484	  /* Put a new line in the end as a splitter */
485	  VTR_LOG("\n");
486	}
