488	template <class T>
489	int Shell<T>::exit_code() const {
490	  /* Check all the command status, if we see fatal errors or minor errors, we drop an error code */
491	  int exit_code = 0;
492	  for (const int& status : command_status_) {
493	    if ( (status == CMD_EXEC_FATAL_ERROR)
494	      || (status == CMD_EXEC_MINOR_ERROR) ) {
495	      exit_code = 1;
496	      break;
497	    }
498	  } 
499	
500	  return exit_code;
501	}
502	
503	template <class T>
504	int Shell<T>::execution_errors() const {
505	  /* Show error message if we detect any errors */
506	  int num_err = 0;
507	
508	  for (const ShellCommandId& cmd : commands()) {
509	    if (command_status_[cmd] == CMD_EXEC_FATAL_ERROR) {
510	      VTR_LOG_ERROR("Command '%s' execution has fatal errors\n",
511	                    commands_[cmd].name().c_str());
512	      num_err++;
513	    }
514	      
515	    if (command_status_[cmd] == CMD_EXEC_MINOR_ERROR) {
516	      VTR_LOG_ERROR("Command '%s' execution has minor errors\n",
517	                    commands_[cmd].name().c_str());
518	      num_err++;
519	    }
520	  }
521	
522	  return num_err;
523	}
524	
525	template <class T>
526	void Shell<T>::exit(const int& init_err) const {
527	  /* Check all the command status, if we see fatal errors or minor errors, we drop an error code */
528	  int shell_exit_code = exit_code() | init_err;
529	
530	  /* Show error message if we detect any errors */
531	  int num_err = init_err;
532	  if (CMD_EXEC_SUCCESS != shell_exit_code) {
533	    VTR_LOG("\n");
534	    num_err += execution_errors();
535	  }
536	
537	  VTR_LOG("\nFinish execution with %d errors\n",
538	            num_err);
539	
540	  VTR_LOG("\nThe entire %s flow took %g seconds\n",
541	          name_.c_str(),
542	          (double)(std::clock() - time_start_) / (double)CLOCKS_PER_SEC);
543	
544	  VTR_LOG("\nThank you for using %s!\n",
545	          name().c_str());
546	
547	  std::exit(shell_exit_code);
548	}
