550	/************************************************************************
551	 * Private executors
552	 ***********************************************************************/
553	template <class T>
554	int Shell<T>::execute_command(const char* cmd_line,
555	                               T& common_context, const bool& allow_hidden_command) {
556	  openfpga::StringToken tokenizer(cmd_line);  
557	  tokenizer.add_delim(' ');
558	  /* Do not split the string in each quote "", as they should be a piece */
559	  std::vector<size_t> quote_anchors = tokenizer.find_positions('\"');
560	  /* Quote should be not be started with! */
561	  if (!quote_anchors.empty() && quote_anchors.front() == 0) {
562	    VTR_LOG("Quotes (\") should NOT be the first charactor in command line: '%s'\n", cmd_line);
563	    return CMD_EXEC_FATAL_ERROR;
564	  }
565	  /* Quotes must be in pairs! */
566	  if (0 != quote_anchors.size() % 2) {
567	    VTR_LOG("Quotes (\") are not in pair in command line: '%s'\n", cmd_line);
568	    return CMD_EXEC_FATAL_ERROR;
569	  }
570	  /* Tokenize the line based on anchors */
571	  std::vector<std::string> tokens;
572	  if (quote_anchors.empty()) {
573	    tokens = tokenizer.split(" ");
574	  } else {
575	    tokens = tokenizer.split_by_chunks('\"');
576	  } 
577	
578	  /* Find if the command name is valid */
579	  ShellCommandId cmd_id = command(tokens[0]);
580	  if (ShellCommandId::INVALID() == cmd_id) {
581	    VTR_LOG("Try to call a command '%s' which is not defined!\n",
582	            tokens[0].c_str());
583	    return CMD_EXEC_FATAL_ERROR;
584	  }
585	  /* Do not allow hidden commands if specified */
586	  if (!allow_hidden_command) {
587	    if (command_hidden_[cmd_id]) {
588	      VTR_LOG("Try to call a command '%s' which is not defined!\n",
589	              tokens[0].c_str());
590	      return CMD_EXEC_FATAL_ERROR;
591	    }
592	  }
593	
594	  /* Check the dependency graph to see if all the prequistics have been met */
595	  for (const ShellCommandId& dep_cmd : command_dependencies_[cmd_id]) {
596	    if ( (CMD_EXEC_NONE == command_status_[dep_cmd])
597	      || (CMD_EXEC_FATAL_ERROR == command_status_[dep_cmd]) ) {
598	      VTR_LOG("Command '%s' is required to be executed before command '%s'!\n",
599	              commands_[dep_cmd].name().c_str(), commands_[cmd_id].name().c_str());
600	      /* Echo the command help desk */
601	      print_command_options(commands_[cmd_id]);
602	      command_status_[cmd_id] = CMD_EXEC_FATAL_ERROR;
603	      return CMD_EXEC_FATAL_ERROR;
604	    } 
605	  }
606	
607	  /* Find the command! Parse the options 
608	   * Note:
609	   * Macro command will not be parsed! It will be directly executed
610	   */
611	  if (MACRO == command_execute_function_types_[cmd_id]) {
612	    /* Convert the tokens from string to char */
613	    char** argv = (char**)malloc(tokens.size() * sizeof(char*));
614	    for (size_t itok = 0; itok < tokens.size(); ++itok) {
615	      argv[itok] = (char*)malloc((tokens[itok].length() + 1) * sizeof(char));
616	      strcpy(argv[itok], tokens[itok].c_str());
617	    }
618	    /* Execute the marco function and record the execution status */
619	    command_status_[cmd_id] = command_macro_execute_functions_[cmd_id](tokens.size(), argv);
620	    /* Free the argv */
621	    for (size_t itok = 0; itok < tokens.size(); ++itok) {
622	      free(argv[itok]);
623	    }
624	    free(argv);
625	
626	    /* Finish for macro command, return */
627	    return command_status_[cmd_id];
628	  }
629	 
630	  /* Reset the command parse results to initial status 
631	   * Avoid conflict when calling the same command in the second time 
632	   */
633	  command_contexts_[cmd_id].reset();
634	  if (false == parse_command(tokens, commands_[cmd_id], command_contexts_[cmd_id])) {
635	    /* Echo the command */
636	    print_command_options(commands_[cmd_id]);
637	    command_status_[cmd_id] = CMD_EXEC_FATAL_ERROR;
638	    return CMD_EXEC_FATAL_ERROR;
639	  }
640	 
641	  /* Parse succeed. Let user to confirm selected options */ 
642	  print_command_context(commands_[cmd_id], command_contexts_[cmd_id]);
643	
644	  /* Execute the command depending on the type of function ! */ 
645	  switch (command_execute_function_types_[cmd_id]) {
646	  case PLUGIN:
647	    command_status_[cmd_id] = command_plugin_execute_functions_[cmd_id](this, common_context, commands_[cmd_id], command_contexts_[cmd_id]);
648	    break;
649	  case CONST_STANDARD:
